        {/* Compact Header - ORANGE GRADIENT */}
        <div className="flex-none bg-gradient-to-r from-orange-600 to-amber-600 px-6 py-3 text-white flex flex-col md:flex-row items-center justify-between gap-4 shadow-md z-20">
            <div className="flex items-center gap-3">
                <div className="bg-white/20 p-2 rounded-lg"><Sparkles className="text-yellow-200 w-5 h-5" /></div>
                <h1 className="text-xl font-display font-extrabold tracking-tight">SỨC MẠNH AI - by Nam Lê 098.102.8794 </h1>
            </div>

            {/* Navigation Tabs - Updated */}
            <div className="flex gap-1 overflow-x-auto w-full md:w-auto pb-1 md:pb-0 custom-scrollbar">
                {[
                  { id: 'user_guide', label: 'Hướng Dẫn', icon: BookOpen },
                  { id: 'studio', label: 'Ghép Ảnh', icon: Sparkles },
                  { id: 'virtual_try_on', label: 'Thử Đồ Ảo', icon: Shirt },
                  { id: 'ai_image_generator', label: 'Tạo Ảnh AI', icon: Camera }, // Merged Tab
                  { id: 'content_genius', label: 'Content', icon: PenTool },
                  { id: 'text_to_speech', label: 'Giọng Đọc', icon: Mic },
                  { id: 'prompt_builder', label: 'Prompt AI', icon: Lightbulb }
                ].map(tab => (
                   <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`px-3 py-1.5 rounded-lg text-sm font-display font-bold flex items-center gap-2 transition-all whitespace-nowrap
                    ${activeTab === tab.id 
                        ? 'bg-white text-orange-700 shadow-sm' 
