                      {mode === 'poster' ? <Megaphone size={32} className="mx-auto mb-2 opacity-50" /> : <Camera size={32} className="mx-auto mb-2 opacity-50" />}
                      <p className="text-sm font-medium font-body">Chưa Có Ảnh</p>
                      <p className="text-xs mt-1 font-body">Kết quả sẽ hiển thị ở đây</p>
                  </div>
              )}
          </div>

          {/* Video Prompt Generation Section (Only for Marketing Mode) */}
          {mode === 'marketing' && marketingResult && (
             <div className="mt-2 border-t pt-4 border-gray-200 animate-in fade-in slide-in-from-bottom-2">
                <button 
                    onClick={handleGenerateVideoPrompt}
                    disabled={isVideoGenerating}
                    className="w-full py-2 bg-amber-100 text-amber-700 font-display font-bold rounded-lg hover:bg-amber-200 transition flex items-center justify-center gap-2 text-sm"
                >
                    {isVideoGenerating ? <RefreshCw className="animate-spin" size={14}/> : <Video size={14}/>}
