        </div>
        <h3 className="font-bold font-display text-slate-800 text-sm mb-2 leading-tight">{item.title}</h3>
        {item.posting_advice && (
            <div className="mb-2 bg-amber-50 border border-amber-100 rounded-lg p-2">
                <div className="flex items-start gap-2">
                    <ScanEye size={12} className="text-amber-600 mt-0.5 shrink-0" />
                    <div><span className="text-[9px] font-bold text-amber-700 uppercase block mb-0.5">Lưu ý Safe-Zone:</span><p className="text-[10px] font-body text-amber-800 leading-snug line-clamp-2 hover:line-clamp-none">{item.posting_advice}</p></div>
                </div>
            </div>
        )}
        <div className="mb-2">
          <label className="text-[9px] uppercase font-bold text-slate-400 mb-1 block">Prompt tạo ảnh:</label>
          <textarea value={promptContent} onChange={(e) => setPromptContent(e.target.value)} className="w-full bg-slate-50 p-2 rounded-lg border border-slate-200 font-mono text-[10px] text-slate-600 leading-relaxed h-16 overflow-y-auto custom-scrollbar focus:ring-2 focus:ring-orange-200 outline-none resize-none transition-all hover:bg-white" />
          <button onClick={() => handleCopyText(promptContent, 'prompt')} className={`mt-1 w-full py-1 rounded text-[10px] font-medium border flex items-center justify-center gap-1 transition-all ${copiedPrompt ? 'bg-green-50 text-green-600 border-green-200' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}>{copiedPrompt ? <Check size={10}/> : <Copy size={10}/>} {copiedPrompt ? 'Đã copy' : 'Copy'}</button>
        </div>
        {(caption || isGeneratingCaption) && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
             <div className="flex items-center gap-2 mb-1"><label className="text-[9px] uppercase font-bold text-red-500 block">Caption:</label>{isGeneratingCaption && <RefreshCw size={10} className="animate-spin text-red-500"/>}</div>
             <textarea value={caption} readOnly className="w-full bg-red-50/50 p-2 rounded-lg border border-red-100 font-body text-[11px] text-slate-700 leading-relaxed h-20 overflow-y-auto custom-scrollbar focus:ring-2 focus:ring-red-200 outline-none resize-none" placeholder="Đang viết caption..." />
             <button onClick={() => handleCopyText(caption, 'caption')} disabled={!caption} className={`mt-1 w-full py-1 rounded text-[10px] font-medium border flex items-center justify-center gap-1 transition-all ${copiedCaption ? 'bg-green-50 text-green-600 border-green-200' : 'bg-white text-red-600 border-red-200 hover:bg-red-50'}`}>{copiedCaption ? <Check size={10}/> : <Copy size={10}/>} {copiedCaption ? 'Đã copy' : 'Copy'}</button>
          </div>
        )}
      </div>
      <div className="p-2 bg-slate-50 border-t border-slate-100">
        <button onClick={generateCaption} className="w-full py-2 rounded-lg font-bold font-display text-xs flex items-center justify-center gap-2 transition-all bg-gradient-to-r from-slate-800 to-slate-700 text-white hover:shadow-md transform hover:-translate-y-0.5 active:translate-y-0">{isGeneratingCaption ? <RefreshCw className="animate-spin" size={14} /> : <MessageSquare size={14} />} {caption ? 'Viết lại Caption' : 'Gợi ý Caption'}</button>
      </div>
    </div>
  );
};

