      setIsGeneratingPodcast(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const res = await ai.models.generateContent({model:'gemini-2.5-flash', contents: `Viết kịch bản podcast ngắn 30s về chủ đề: ${inputText}. Giọng văn thân thiện, chia sẻ.`});
