                            <textarea value={soraSeqDescription} onChange={(e) => setSoraSeqDescription(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm h-24 resize-none outline-none focus:border-red-400 font-body" placeholder="Nhập cốt truyện chính cho chuỗi video..." />
