                         <div className="grid grid-cols-3 gap-3">
                             <div>
                                <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Nền tảng</label>
                                <select value={soraSeqPlatform} onChange={(e) => setSoraSeqPlatform(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-xs font-body"><option value="tiktok">TikTok (9:16)</option><option value="youtube">YouTube (16:9)</option></select>
                             </div>
                             <div>
                                <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Thời lượng Clip</label>
                                <select value={soraSeqClipDuration} onChange={(e) => setSoraSeqClipDuration(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-xs font-body"><option value="5s">5s</option><option value="8s">8s</option><option value="10s">10s</option></select>
                             </div>
                             <div>
                                <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Style</label>
                                <select value={soraSeqVideoStyle} onChange={(e) => setSoraSeqVideoStyle(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-xs font-body"><option value="cinematic">Điện ảnh</option><option value="vlog">Vlog đời thường</option><option value="anime">Anime</option></select>
