                         <button onClick={handleSoraSeqGeneratePrompt} disabled={isSoraSeqGeneratingPrompts || !soraSeqDescription} className="w-full py-3 bg-gradient-to-r from-red-600 to-pink-600 text-white font-bold rounded-xl shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2">{isSoraSeqGeneratingPrompts ? <RefreshCw className="animate-spin"/> : <Film/>} Tạo Chuỗi Video</button>
                    </div>
                 </div>
