                        </div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                        <div>
                            <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Trigger Word</label>
                            <input type="text" value={bananaTriggerWord} onChange={(e) => setBananaTriggerWord(e.target.value)} className="w-full p-2 border border-slate-200 rounded-lg text-sm font-body" placeholder="Tên nhân vật (ví dụ: mr_nam)" />
