      const genderMap: Record<string, string> = { male: 'Male', female: 'Female' };
      const regionMap: Record<string, string> = { north: 'Northern Vietnamese', central: 'Central Vietnamese', south: 'Southern Vietnamese' };
      const ageMap: Record<string, string> = { young: 'Gen Z/Young', middle: 'Professional/Adult', old: 'Warm/Elderly' };

      let audioDescription = "";

      // 1. Thêm SFX (Gộp tất cả lựa chọn)
      const sfxPrompt = selectedSoundEffects.map(key => soundEffects[key].keyword).join(" ");

      // 2. Thêm Voice nếu có
      if (hasVoice) {
         audioDescription = `
      Audio Character: A ${ageMap[voiceAge]} ${genderMap[voiceGender]} voice speaking Vietnamese with a ${regionMap[voiceRegion]} accent. 
      The character is reviewing the product enthusiastically. 
      ${script ? `Spoken lines: "${script}"` : ''}
      ${sfxPrompt}
         `.trim();
      } else {
        audioDescription = `
      Audio: No spoken dialogue.
      ${sfxPrompt}
      Background Audio: Ambient room noise matching the visual style.
        `.trim();
      }

      // Cấu trúc Prompt
      const promptStructure = `
${styleData.promptKeywords}. 
${getCameraDescription(cameraAngle, selectedStyle)}. 
${actionDescription}${baseDesc}. 
Texture quality is photorealistic, highly detailed, sora2 native quality.
--
${audioDescription}
      `.trim().replace(/\s+/g, ' ');

      setGeneratedPrompt(promptStructure);
      setIsGenerating(false);
    }, 800);
  };

  const getCameraDescription = (angle: string, style: string) => {
    switch(angle) {
      case 'pov': return 'First-person POV shot showing human hands';
      case 'top-down': return 'Symmetrical top-down view laying flat';
      case 'macro': return 'Extreme macro shot focusing on texture details';
      default: return 'Cinematic close-up shot at eye level';
    }
  };

  const copyToClipboard = () => {
    const textArea = document.createElement("textarea");
    textArea.value = generatedPrompt;
    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    textArea.style.top = "0";
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();
    try { document.execCommand('copy'); } catch (err) { console.error('Lỗi copy', err); }
    document.body.removeChild(textArea);
  };

  return (
    <div className="bg-slate-900 text-slate-100 font-sans selection:bg-purple-500 selection:text-white min-h-full">
      {/* Header */}
      <header className="bg-slate-800 border-b border-slate-700 p-4 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto flex items-center gap-3">
          <div className="bg-gradient-to-br from-purple-500 to-pink-500 p-2 rounded-lg">
            <Box className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-purple-400 to-pink-400">
            SoraPrompt Gen
          </h1>
          <span className="text-xs px-2 py-1 bg-slate-700 rounded-full text-slate-400">Pro</span>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Cột trái: Input Form */}
        <div className="space-y-6">

          {/* Section 1: Thông tin sản phẩm */}
          <section className="bg-slate-800 rounded-2xl p-6 border border-slate-700 shadow-lg">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2 text-purple-300">
              <Upload className="w-5 h-5" /> 
              1. Thông tin Sản phẩm
            </h2>

            <div className="mb-4">
               {/* Image Upload UI (Simplified for brevity) */}
               <div className="relative group cursor-pointer border-2 border-dashed border-slate-600 rounded-xl p-4 hover:border-purple-500 transition-colors bg-slate-750 text-center h-32 flex flex-col justify-center items-center">
                <input type="file" accept="image/*" onChange={handleImageUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                {imagePreview ? (
                   <img src={imagePreview} alt="Preview" className="h-full w-full object-contain rounded-lg" />
                ) : (
                  <>
                    <Upload className="w-6 h-6 opacity-50 mb-2" />
                    <span className="text-xs text-slate-400">Tải ảnh sản phẩm (Optional)</span>
                  </>
                )}
              </div>
            </div>

            <div className="grid gap-3">
              <input 
                type="text" 
                value={productName}
                onChange={(e) => setProductName(e.target.value)}
                placeholder="Tên sản phẩm (VD: Son dưỡng môi, Tai nghe...)"
                className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 focus:ring-2 focus:ring-purple-500 outline-none text-slate-200 placeholder-slate-500"
              />
              <textarea 
                value={productDesc}
                onChange={(e) => setProductDesc(e.target.value)}
                placeholder="Mô tả đặc điểm (Màu sắc, chất liệu...)"
                className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 h-20 focus:ring-2 focus:ring-purple-500 outline-none resize-none text-slate-200 placeholder-slate-500"
              />
            </div>
          </section>

          {/* Section 2: Kịch bản & Âm thanh (UPDATED) */}
          <section className="bg-slate-800 rounded-2xl p-6 border border-slate-700 shadow-lg border-l-4 border-l-pink-500">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2 text-pink-300">
              <Gift className="w-5 h-5" /> 
              2. Kịch bản & Âm thanh
            </h2>

            {/* Checkbox Gift Box */}
            <div 
              onClick={() => setIsGiftBox(!isGiftBox)}
              className={`flex items-center gap-3 p-3 rounded-xl cursor-pointer border transition-all mb-5 ${isGiftBox ? 'bg-pink-500/20 border-pink-500' : 'bg-slate-750 border-slate-600 hover:bg-slate-700'}`}
            >
              <div className={`w-5 h-5 rounded border flex items-center justify-center ${isGiftBox ? 'bg-pink-500 border-pink-500' : 'border-slate-400'}`}>
                {isGiftBox && <Sparkles className="w-3 h-3 text-white" />}
              </div>
